              </h3>
              <ul className="space-y-2">
                {data.importantTopics.map((t, i) => (
                  <li key={i} className="flex items-center gap-2 text-sm text-muted-foreground">
                    <Target className="h-3.5 w-3.5 text-primary shrink-0" />
                    {t}
